ll lis(ll* a, ll n, ll* dp) {

  fill(dp, dp + n, INF);

  for (ll i = 0; i < n; i++) *lower_bound(dp, dp + n, a[i]) = a[i];

  return (ll)(lower_bound(dp, dp + n, INF) - dp);

}



