ll binarySearch(function<bool(ll)> check, ll ok, ll ng) {

  while ((ok - ng > 1) || (ng - ok > 1)) {

    ll mid = (ok + ng) / 2;

    if (check(mid)) ok = mid;

    else ng = mid;

  }

  return ok;

}



double binarySearchDouble(function<bool(double)> check, double ok, double ng) {

